// Get all items from the CleanUpAppointment node
const items = $('CleanUpAppointment1').all();

// Add your custom variables to each item
for (const item of items) {
    item.json.ConsentFormFilled = true;
    item.json.ConsentFormSubmitted = true;
    item.json.ClientAppointmentID = $('Start').first().json.body_data_appointments_firstItem[0].id;
}

return items;

const item = $input.first().json;

// Get data and turn it into an object if it's a JSON string
let data = item.data;

if (typeof data === 'string') {
  try {
    data = JSON.parse(data);
  } catch (error) {
    throw new Error('data is not valid JSON: ' + data);
  }
} else if (!data || typeof data !== 'object') {
  data = {};
}

// Pull out first file for the signature
const file0 = (data.file && data.file[0]) || {};

const output = {
  ...item,      // keep original fields (guest_data, is_form_submitted, etc.)
  ...data,      // expand fields from parsed data
  signatureUrl: file0.presignedUrl || null,
};

// Optional: remove nested data now that it's expanded
delete output.data;

return [
  {
    json: output,
  },
];

// CUSTOM DELIVERY NODE

const items = $input.all();

// Get the custom address from the first input item
const customAddress = $input.first().json.textField || '';

for (const item of items) {
	const json = item.json;

	// --- 1. Rename fields for product & quantity ---
	if (json.select16 !== undefined) {
		json.product = json.select16;
		delete json.select16;
	}

	if (json.textField16 !== undefined) {
		json.quantity = json.textField16;
		delete json.textField16;
	}

	// --- 2. Build delivery address for CUSTOM deliveries ---
	if (json.DeliveryLocation === 'custom') {
		// Full address typed by user (same value as $input.first().json.textField)
		json.DeliveryAddressFull = customAddress;
	}
}

return items;

const items = $input.all();

for (const item of items) {
	const json = item.json;

	// --- Rename fields ---
	if (json.select13 !== undefined) {
		json.doctorsDirections = json.select13;
		delete json.select13;
	}

	// --- Remove unwanted top-level fields ---
	delete json.guest_data;
	delete json.selectBoxes;
	delete json.file;
	delete json.contentMacros;
	delete json.signatureUrl;
	delete json.dateTime1;
	delete json.dateTime;
	delete json.ClientAppointmentID;

	// Add more deletes here as needed
}

return items;

// Get all items from the CleanUpAppointment node
const items = $('CleanUpAppointment1').all();

// Add your custom variables to each item
for (const item of items) {
    item.json.ConsentFormFilled = $input.first().json.is_filled;
    item.json.ConsentFormSubmitted = $input.first().json.is_submitted;
    item.json.ClientAppointmentID = $('GrabUserDetails').first().json.AppointmentID;
}

return items;

// GUEST DELIVERY NODE

const items = $input.all();

for (const item of items) {
	const json = item.json;

	// --- 1. Rename fields for product & quantity ---
	if (json.select16 !== undefined) {
		json.product = json.select16;
		delete json.select16;
	}

	if (json.textField16 !== undefined) {
		json.quantity = json.textField16;
		delete json.textField16;
	}

	// --- 2. Build delivery address for GUEST deliveries ---
	// Using contentMacros.content14
	if (json.DeliveryLocation === 'guest'
		&& json.contentMacros
		&& json.contentMacros.content14) {

		const c14 = json.contentMacros.content14;

		json.DeliveryAddress1 = c14['[GuestAddress1]'] || '';
		json.DeliveryCity     = c14['[GuestCity]'] || '';

		json.DeliveryAddressFull = [
			json.DeliveryAddress1,
			json.DeliveryCity,
		].filter(Boolean).join(', ');
	}
}

return items;

// Get the raw DOB
const rawDob = $('Start').first().json.personal_info_date_of_birth_firstItem;

// Convert to dd/MM/yyyy format
let formattedDob = null;

if (rawDob) {
  const dateOnly = rawDob.split("T")[0]; // "1979-03-25"
  const [year, month, day] = dateOnly.split("-");
  formattedDob = `${day}/${month}/${year}`;
}

// Build the output
return [
  {
    json: {
      AppointmentID: $('Start').first().json.body_data_appointments_firstItem[0].id,
      CustomerFirstName: $('Start').first().json.body_data_guest_first_name_firstItem,
      CustomerLastName: $('Start').first().json.body_data_guest_last_name_firstItem,
      CustomerCode: $('Start').first().json.code_firstItem,
      CustomerID: $('Start').first().json.body_data_guest_id_firstItem,
      CustomerDOB: formattedDob,
      CustomerEmail: $('Start').first().json.personal_info_email_firstItem,
      CustomerGender: $('Start').first().json.personal_info_gender_name_firstItem,
      CustomerCenterID: $('Start').first().json.body_data_center_id_firstItem,
    }
  }
];

// Get all incoming items
const items = $input.all();

for (const item of items) {
	const json = item.json;

	// --- 1. Rename fields for product & quantity ---
	if (json.select16 !== undefined) {
		json.product = json.select16;
		delete json.select16;
	}

	if (json.textField16 !== undefined) {
		json.quantity = json.textField16;
		delete json.textField16;
	}

	// --- 2. Build delivery address for CLINIC deliveries ---
	// We’re using contentMacros.content15 for clinic
	if (json.DeliveryLocation === 'clinic'
		&& json.contentMacros
		&& json.contentMacros.content15) {

		const c15 = json.contentMacros.content15;

		// Map macros to cleaner fields
		json.DeliveryAddress1 = c15['[CustomMacro2]'] || '';
		json.DeliverySuburb  = c15['[CustomMacro3]'] || '';
		json.DeliveryCity    = c15['[CustomMacro4]'] || '';
		json.DeliveryPostcode = c15['[CustomMacro5]'] || '';

		// Optional: combined address line if you want it
		json.DeliveryAddressFull = [
			json.DeliveryAddress1,
			json.DeliverySuburb,
			json.DeliveryCity,
			json.DeliveryPostcode,
		].filter(Boolean).join(', ');
	}
}

// Return updated items
return items;

